import React, { useEffect, useState, useRef } from 'react';
import { ReactFlow, Controls, Background, useNodesState, useEdgesState } from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import mermaid from 'mermaid';
import { useDiagramStore } from '../store/useDiagramStore';
import { Maximize, RefreshCw } from 'lucide-react';

mermaid.initialize({
  startOnLoad: false,
  theme: 'default',
  securityLevel: 'loose',
});

// A custom node that simply renders raw HTML (SVG from mermaid)
const MermaidNode = ({ data }: { data: { svg: string } }) => {
    return (
        <div 
            className="mermaid-wrapper bg-white shadow-lg p-8 rounded-xl border border-slate-200"
            dangerouslySetInnerHTML={{ __html: data.svg }} 
        />
    );
};

const nodeTypes = {
    mermaidNode: MermaidNode
};

export const PaneCenterCanvas = () => {
    const { mermaidCode } = useDiagramStore();
    const [svgContent, setSvgContent] = useState<string>('');
    const [error, setError] = useState<string | null>(null);
    const renderId = useRef(0);

    const [nodes, setNodes, onNodesChange] = useNodesState([]);
    const [edges, setEdges, onEdgesChange] = useEdgesState([]);

    useEffect(() => {
        const renderDiagram = async () => {
             const currentId = ++renderId.current;
             try {
                // Clear previous error
                setError(null);
                const { svg } = await mermaid.render(\`mermaid-diagram-\${currentId}\`, mermaidCode);
                
                // Only update if this is still the most recent render request
                if (currentId === renderId.current) {
                    setSvgContent(svg);
                    
                    // We only have one big node holding the entire diagram
                    setNodes([
                        {
                            id: 'root-mermaid-node',
                            position: { x: 0, y: 0 },
                            type: 'mermaidNode',
                            data: { svg: svg },
                            draggable: true,
                        }
                    ]);
                }
             } catch (err: any) {
                console.error("Mermaid Render Error:", err);
                if (currentId === renderId.current) {
                     setError(err.message || 'Syntax Error in Diagram Code');
                }
             }
        };

        const timeout = setTimeout(renderDiagram, 300); // 300ms debounce
        return () => clearTimeout(timeout);
    }, [mermaidCode, setNodes]);


    return (
        <div className="flex-1 bg-slate-50 relative h-full flex flex-col">
            <div className="absolute top-4 left-4 z-10 bg-white shadow-sm rounded-md px-3 py-1.5 border border-slate-200 flex items-center gap-2">
                 <span className="text-sm font-medium text-slate-700">Visual Canvas</span>
            </div>

            {error ? (
                 <div className="absolute inset-0 z-20 flex items-center justify-center p-8 bg-white/80 backdrop-blur-sm">
                    <div className="bg-red-50 text-red-700 p-4 rounded-lg shadow-md max-w-md border border-red-200">
                        <h3 className="font-bold flex items-center gap-2 mb-2">
                            <RefreshCw size={16} className="animate-spin" />
                            Render Error
                        </h3>
                        <pre className="text-xs overflow-auto whitespace-pre-wrap">{error}</pre>
                    </div>
                </div>
            ) : null}

            <div className="flex-1 w-full h-full">
                <ReactFlow
                    nodes={nodes}
                    edges={edges}
                    onNodesChange={onNodesChange}
                    onEdgesChange={onEdgesChange}
                    nodeTypes={nodeTypes}
                    fitView
                    minZoom={0.1}
                    maxZoom={4}
                    proOptions={{ hideAttribution: true }}
                >
                    <Background color="#cbd5e1" gap={16} />
                    <Controls showInteractive={false} className="bg-white shadow-md border-slate-200 rounded-md overflow-hidden" />
                </ReactFlow>
            </div>
        </div>
    );
};

import { create } from 'zustand';

// Basic structure for our Abstract Syntax Tree (AST) representing a DFD Level 0 diagram.
export interface DfdNode {
  id: string;
  label: string;
  type: 'process' | 'entity' | 'datastore';
}

export interface DfdEdge {
  id: string;
  source: string;
  target: string;
  label: string;
}

interface DiagramState {
  // Raw text representation
  mermaidCode: string;
  
  // AST representation
  nodes: DfdNode[];
  edges: DfdEdge[];
  
  // Actions
  setMermaidCode: (code: string) => void;
  updateAstFromCode: (code: string) => void;
  updateCodeFromAst: (nodes: DfdNode[], edges: DfdEdge[]) => void;
  
  // Form Actions
  addNode: (node: Omit<DfdNode, 'id'>) => void;
  updateNode: (id: string, updates: Partial<DfdNode>) => void;
  removeNode: (id: string) => void;
  addEdge: (edge: Omit<DfdEdge, 'id'>) => void;
  updateEdge: (id: string, updates: Partial<DfdEdge>) => void;
  removeEdge: (id: string) => void;
}

const DEFAULT_CODE = `graph TD
  %% DiagramSathi Generated DFD
  User[User] -->|Input Data| System((Main System))
  System -->|Store Data| DB[(Database)]
`;

// A very naive parser/generator for MVP.
// In a production app, we would use a robust parser (e.g. jison or regex tokenizer)
const generateMermaidFromAst = (nodes: DfdNode[], edges: DfdEdge[]): string => {
  let code = 'graph TD\n  %% DiagramSathi Generated DFD\n';
  
  nodes.forEach(n => {
    if (n.type === 'process') code += `  ${n.id}((${n.label}))\n`;
    else if (n.type === 'datastore') code += `  ${n.id}[(${n.label})]\n`;
    else code += `  ${n.id}[${n.label}]\n`; // entity default
  });
  
  edges.forEach(e => {
    code += `  ${e.source} -->|${e.label}| ${e.target}\n`;
  });
  
  return code;
};

// Extremely naive simplistic parsing for MVP.
const parseMermaidToAst = (code: string) => {
    // This is a placeholder for actual robust biderectional parsing.
    // Full AST sync from raw text is complex. For this MVP, we mainly rely on Form->AST->Code.
    // If user types raw code, we accept it for rendering, but might lose structural mapping in the exact form 
    // without advanced regex parsing. We'll implement basic regex matching if time permits.
    console.log("Parsing from code:", code.length);
    return { nodes: [], edges: [] }; 
};


export const useDiagramStore = create<DiagramState>((set, get) => ({
  mermaidCode: DEFAULT_CODE,
  nodes: [
    { id: 'User', label: 'User', type: 'entity' },
    { id: 'System', label: 'Main System', type: 'process' },
    { id: 'DB', label: 'Database', type: 'datastore' },
  ],
  edges: [
    { id: 'e1', source: 'User', target: 'System', label: 'Input Data' },
    { id: 'e2', source: 'System', target: 'DB', label: 'Store Data' },
  ],

  setMermaidCode: (code) => {
    set({ mermaidCode: code });
    // Attempt bidirectional parse
    get().updateAstFromCode(code);
  },
  
  updateAstFromCode: (code) => {
      // Stub for MVP logic
  },
  
  updateCodeFromAst: (nodes, edges) => {
    const newCode = generateMermaidFromAst(nodes, edges);
    set({ mermaidCode: newCode });
  },

  addNode: (nodeData) => {
    const id = \`n_\${Date.now()}\`;
    const newNode = { ...nodeData, id };
    const newNodes = [...get().nodes, newNode];
    set({ nodes: newNodes });
    get().updateCodeFromAst(newNodes, get().edges);
  },

  updateNode: (id, updates) => {
    const newNodes = get().nodes.map(n => n.id === id ? { ...n, ...updates } : n);
    set({ nodes: newNodes });
    get().updateCodeFromAst(newNodes, get().edges);
  },
  
  removeNode: (id) => {
      const newNodes = get().nodes.filter(n => n.id !== id);
      // Remove connected edges
      const newEdges = get().edges.filter(e => e.source !== id && e.target !== id);
      set({ nodes: newNodes, edges: newEdges });
      get().updateCodeFromAst(newNodes, newEdges);
  },

  addEdge: (edgeData) => {
    const id = \`e_\${Date.now()}\`;
    const newEdge = { ...edgeData, id };
    const newEdges = [...get().edges, newEdge];
    set({ edges: newEdges });
    get().updateCodeFromAst(get().nodes, newEdges);
  },
  
  updateEdge: (id, updates) => {
      const newEdges = get().edges.map(e => e.id === id ? { ...e, ...updates } : e);
      set({ edges: newEdges });
      get().updateCodeFromAst(get().nodes, newEdges);
  },

  removeEdge: (id) => {
      const newEdges = get().edges.filter(e => e.id !== id);
      set({ edges: newEdges });
      get().updateCodeFromAst(get().nodes, newEdges);
  }
}));
